<template>
  <div>
    <h3>名称</h3>
    <van-field
      v-model="form.name"
      autosize
      type="input"
      placeholder="请输入"
      vertical
    />
    <h3 style="margin-top: 16px;">描述</h3>
    <van-field
      v-model="form.description"
      autosize
      rows="3"
      type="textarea"
      placeholder="请输入"
      vertical
    />
    <a-button type="primary" style="width: 100%; height: 48px; margin-top: 16px; font-size: 24px;" @click="save">
      {{ this.$route.name === 'detailConfig' ? '修改' : this.$route.name === 'add' ? '新建' : '保存' }}
    </a-button>
  </div>
</template>
<script>
import ListItem from '@/components/ListItem.vue'
import { getVoteContestantDetail, updateContestant, addContestant } from '@/api/voteContestant'
export default {
  components: { ListItem },
  data() {
    return {
      form: {
        voteId: null,
        name: '',
        description: '',
        avatar: '',
        displayOrder: 1,
      },
    }
  },
  mounted() {
    if (this.$route.name === 'contestantDetail') {
      getVoteContestantDetail(this.$route.params.cid).then(res => {
        this.form = res
      })
    } else if (this.$route.name === 'contestantAdd') {
      this.form.voteId = this.$route.params.id
    }
  },
  methods: {
    save() {
      if (this.$route.name === 'contestantDetail') {
        updateContestant(this.form).then(res => {
          this.$message.success('已修改')
          this.$router.go(-1)
        })
      } else if (this.$route.name === 'contestantAdd') {
        addContestant(this.form).then(res => {
          this.$message.success('已添加')
          this.$router.go(-1)
        })
      }
    },
  },
}
</script>
<style lang="less" scoped>
::v-deep .ant-card-body {
  padding: 0px !important;
}
::v-deep .van-cell__title {
  span {
    color: #333;
    font-size: 20px;
  }
}
::v-deep .van-field__control, .van-cell__value {
  font-size: 20px;
}
// ::v-deep .acard:first-child {
