<template>
  <div class="label-content-wrapper">
    <span class="label" :style="{ minWidth: minWidth }">{{ label }}</span>
    <div class="spacer"></div>
    <div class="content">
      <a-input
        v-if="type === 'input'"
        v-model="ivalue"
        style="font-size: 20px;
        text-align: right;
        border: 0px;"
        :placeholder="placeholder"
        @input="toggle"
      ></a-input>
      <a-switch
        v-else-if="type === 'switch'"
        v-model="ivalue"
        style="float: right;"
        @change="toggle"
      />
      <div v-else-if="type === 'vantDateTimePicker'" style="float: right;">
        <span v-if="ivalue" style="text-align: right;" @click="vantDateTimePickerShow = true">{{ ivalue | minutes }}</span>
        <span v-else style="text-align: right; font-size: 20px; color: #b2b2b2; margin-right: 10px;" @click="vantDateTimePickerShow = true">点击选择时间</span>
        <van-action-sheet v-model="vantDateTimePickerShow" title="选择时间">
          <div slot="title-left">清空</div>
          <div class="content">
            <van-datetime-picker
              v-model="selectdDate"
              type="datetime"
              title="选择完整时间"
              @confirm="confirm"
              @cancel="cancel"
            />
          </div>
        </van-action-sheet>
      </div>
      <slot v-else></slot>
    </div>
  </div>
</template>

<script>
export default {
  name: 'LabelContent',
  model: {
    prop: 'value',
    event: 'update:value',
  },
  props: {
    value: {
      type: [String, Boolean, Date],
      default: null,
    },
    label: {
      type: String,
      default: '',
    },
    type: {
      type: String,
      default: '',
    },
    placeholder: {
      type: String,
      default: '',
    },
    minWidth: {
      type: String,
      default: 'auto',
    },
  },
  watch: {
    value: {
      immediate: true,
      handler(newVal) {
        this.ivalue = newVal
      },
    },
  },
  data() {
    return {
      ivalue: this.value,
      vantDateTimePickerShow: false,
      selectdDate: null,
    }
  },
  methods: {
    confirm(value) {
      this.ivalue = value
      this.vantDateTimePickerShow = false
      this.toggle()
    },
    cancel() {
      this.vantDateTimePickerShow = false
    },
    toggle() {
      this.$emit('update:value', this.ivalue)
    },
  },
}
</script>

<style lang="less" scoped>
.label-content-wrapper {
  display: flex;
  align-items: center;
  transition: all 0.3s ease;
  width: 100%;
}

/* .label-content-wrapper:hover {
  background: #e9ecef;
  transform: translateY(-2px);
  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.05);
} */

.label {
  flex-shrink: 0;
  font-size: 20px;
  text-shadow: 0.3px 0 0 currentColor, -0.3px 0 0 currentColor, 0 0.3px 0 currentColor, 0 -0.3px 0 currentColor;
  color: #000;
  padding: 5px 0;
}

.spacer {
  width: 20px;
  flex-shrink: 0;
}

.content {
  flex: 1;
  min-width: 0; /* 防止内容溢出 */
}

::v-deep .ant-input:focus {
  box-shadow: none;
}

::v-deep .ant-calendar-picker {
  text-align: right;
}
</style>
